const getPostsByTag = `-- name: GetPostsByTag :many
WITH RECURSIVE h(id) AS (
    SELECT id FROM tags WHERE hides_posts = 1
    UNION
    SELECT tr.child_id FROM tag_relationships tr JOIN h ON tr.parent_id = h.id
)
SELECT p.id, p.title, p.slug, p.content, p.excerpt, p.formatter, p.status, p.type, p.is_featured, p.view_count, p.published_at, p.scheduled_at, p.created_at, p.updated_at, p.author_id, p.thumbnail_path, p.meta_description, p.preview_token, p.preview_expires_at, p.deleted_at, p.css, p.immersive_mode, p.instagram_share, p.instagram_status, p.instagram_media_id, p.instagram_published_at, p.instagram_error, p.instagram_id
FROM posts p
JOIN post_tags pt ON p.id = pt.post_id
WHERE pt.tag_id = ?1
AND p.deleted_at IS NULL
AND (CASE
    WHEN ?2 THEN 1=1
    WHEN ?3 THEN
        p.status = 'published'
        AND NOT EXISTS (
            SELECT 1 FROM post_tags pt2
            WHERE pt2.post_id = p.id AND pt2.tag_id IN (SELECT id FROM h)
        )
    ELSE p.status IN ('published', 'hidden')
END)
ORDER BY p.published_at DESC, p.created_at DESC
LIMIT ?5 OFFSET ?4
`

type GetPostsByTagParams struct {
	TagID               int64       `json:"tag_id"`
	IncludeDrafts       interface{} `json:"include_drafts"`
	PublishedOnlyFilter interface{} `json:"published_only_filter"`
	Offset              int64       `json:"offset"`
	Limit               int64       `json:"limit"`
}

func (q *Queries) GetPostsByTag(ctx context.Context, arg GetPostsByTagParams) ([]Post, error) {
	rows, err := q.db.QueryContext(ctx, getPostsByTag,
		arg.TagID,
		arg.IncludeDrafts,
		arg.PublishedOnlyFilter,
		arg.Offset,
		arg.Limit,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []Post
	for rows.Next() {
		var i Post
		if err := rows.Scan(
			&i.ID,
			&i.Title,
			&i.Slug,
			&i.Content,
			&i.Excerpt,
			&i.Formatter,
			&i.Status,
			&i.Type,
			&i.IsFeatured,
			&i.ViewCount,
			&i.PublishedAt,
			&i.ScheduledAt,
			&i.CreatedAt,
			&i.UpdatedAt,
			&i.AuthorID,
			&i.ThumbnailPath,
			&i.MetaDescription,
			&i.PreviewToken,
			&i.PreviewExpiresAt,
			&i.DeletedAt,
			&i.Css,
			&i.ImmersiveMode,
			&i.InstagramShare,
			&i.InstagramStatus,
			&i.InstagramMediaID,
			&i.InstagramPublishedAt,
			&i.InstagramError,
		&i.InstagramID,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

