const updatePost = `-- name: UpdatePost :one
UPDATE posts
SET title = ?1, slug = ?2, content = ?3, excerpt = ?4, formatter = ?5, status = ?6, type = ?7, is_featured = ?8, thumbnail_path = ?9, meta_description = ?10,
    scheduled_at = ?11,
    published_at = (CASE
        WHEN ?6 = 'published' THEN COALESCE(published_at, CURRENT_TIMESTAMP)
        WHEN ?6 = 'scheduled'  THEN NULL
        ELSE published_at
    END),
    css = ?12,
    immersive_mode = ?13,
    instagram_share = ?14,
    updated_at = CURRENT_TIMESTAMP
WHERE id = ?15 AND author_id = ?16
RETURNING id, title, slug, content, excerpt, formatter, status, type, is_featured, view_count, published_at, scheduled_at, created_at, updated_at, author_id, thumbnail_path, meta_description, preview_token, preview_expires_at, deleted_at, css, immersive_mode, instagram_share, instagram_status, instagram_media_id, instagram_published_at, instagram_error, instagram_id
`

type UpdatePostParams struct {
	Title           string         `json:"title"`
	Slug            string         `json:"slug"`
	Content         string         `json:"content"`
	Excerpt         sql.NullString `json:"excerpt"`
	Formatter       string         `json:"formatter"`
	Status          string         `json:"status"`
	Type            string         `json:"type"`
	IsFeatured      bool           `json:"is_featured"`
	ThumbnailPath   sql.NullString `json:"thumbnail_path"`
	MetaDescription sql.NullString `json:"meta_description"`
	ScheduledAt     sql.NullTime   `json:"scheduled_at"`
	Css             string         `json:"css"`
	ImmersiveMode   string         `json:"immersive_mode"`
	InstagramShare  bool           `json:"instagram_share"`
	ID              int64          `json:"id"`
	AuthorID        int64          `json:"author_id"`
}

func (q *Queries) UpdatePost(ctx context.Context, arg UpdatePostParams) (Post, error) {
	row := q.db.QueryRowContext(ctx, updatePost,
		arg.Title,
		arg.Slug,
		arg.Content,
		arg.Excerpt,
		arg.Formatter,
		arg.Status,
		arg.Type,
		arg.IsFeatured,
		arg.ThumbnailPath,
		arg.MetaDescription,
		arg.ScheduledAt,
		arg.Css,
		arg.ImmersiveMode,
		arg.InstagramShare,
		arg.ID,
		arg.AuthorID,
	)
	var i Post
	err := row.Scan(
		&i.ID,
		&i.Title,
		&i.Slug,
		&i.Content,
		&i.Excerpt,
		&i.Formatter,
		&i.Status,
		&i.Type,
		&i.IsFeatured,
		&i.ViewCount,
		&i.PublishedAt,
		&i.ScheduledAt,
		&i.CreatedAt,
		&i.UpdatedAt,
		&i.AuthorID,
		&i.ThumbnailPath,
		&i.MetaDescription,
		&i.PreviewToken,
		&i.PreviewExpiresAt,
		&i.DeletedAt,
		&i.Css,
		&i.ImmersiveMode,
		&i.InstagramShare,
		&i.InstagramStatus,
		&i.InstagramMediaID,
		&i.InstagramPublishedAt,
		&i.InstagramError,
		&i.InstagramID,
	)
	return i, err
}

